var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"너, 너…. 날 호출한 게 너였어…!? 어떻게…!?","JPN":"あ、あんた……私を呼び出したのがあんただったの……！？　どうやって……！？","ENG":"Y-you're... the one who called for me...?! But how...?!","TWN":"你…找我來的人就是你…！？怎麼會…！？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"어떻게 이 코드를 알고 호출한 거야? 이건 정보부 요원들만 알고 있는 비밀 코드라고!","JPN":"どうやってこのコードで私を呼び出したわけ？　これは情報部のエージェントだけが知ってるシークレットコードなのよ！","ENG":"How did you get my code? This is supposed to be a secret code only for intelligence agents in the Administration!","TWN":"你怎麼會知道我的代碼？這可是只有情報部的特務才知道的機密代碼欸！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"으응? 주인님이니까 메이드의 연락처 정도는 파악하고 있는 게 당연하지 않냐고?","JPN":"ええっ？　ご主人様だから、メイドの連絡先くらいは把握してて当たり前だって？","ENG":"Hmm? It's natural for the master to know their maid's contact info?","TWN":"什麼？主人知道女僕的聯絡方式不是理所當然的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"하나도 안 당연하거든! 그리고 누가 주인님이라는 거야!","JPN":"全っ然当たり前じゃないし！　それに、誰がご主人様なのよ！","ENG":"No, it's not! And you're not my master!","TWN":"一點都不理所當然！而且誰說你是主人的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"전에 메이드 복장이었던 건 어디까지나 업무의 일환이었을 뿐이거든?","JPN":"この前にメイドの服装だったのは、あくまでも業務の一環だったんだからね。","ENG":"I was only wearing the maid dress as a part of work, you know!","TWN":"之前穿女僕裝只是工作需要而已！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그러니까 주인님이라고 불렀던 건 다 무효라고, 무효!","JPN":"だから、ご主人様って呼んだのは全部ナシだよ、ナシ！","ENG":"So me calling you Master didn't count! None of it!","TWN":"所以你才不是我的主人，不算數！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"뭐어? 그럼 평생 돌봐 주겠다고 약속했던 말도 무효냐고…?","JPN":"はあ？　じゃあ、一生世話してあげるって約束したのもナシなのかって……？","ENG":"What? Then does my promise to take care of you forever also not count...?","TWN":"什麼？那承諾會一輩子照顧我的話也不算數嗎…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"으으, 그건….","JPN":"うう、それは……","ENG":"Umm... Well...","TWN":"呃呃，這個嘛…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"아, 아무튼! 무슨 일로 부른 건데? 자꾸 옛날 얘기 꺼낼 거면 나 그냥 간다?","JPN":"と、とにかく！　なんで呼んだの？　昔話ばかりいじってると、私帰るよ？","ENG":"A-anyway! What did you call me here for? If you're going to keep talking about the past, then I'll get going.","TWN":"總…總之！你找我來有什麼事？老是舊事重提的話我要走囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그건… 설마 종신계약서?","JPN":"それ……まさか、終身契約書？","ENG":"Is that... a lifetime contract?","TWN":"那個…該不會是終身契約書？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"잠깐, 잠깐! 너 뭔가 착각하고 있는 거 아니야?","JPN":"ちょっと、ちょっと！　あんた、何か勘違いしてない？","ENG":"Wait, wait a minute! I think you got the wrong idea!","TWN":"等等，等等！你沒搞錯吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"알잖아, 난 지금 정보부 요원이란 말이야.","JPN":"わかってるでしょ？　今の私は情報部のエージェントよ。","ENG":"You already know that I'm an intelligence agent.","TWN":"你也知道，我現在可是情報部的特務。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"제안은 고맙지만… 이젠 메이드 때처럼 항상 곁에서 챙겨줄 자신은 없는데….","JPN":"提案はありがたいけど……もうメイドだった時のようにいつもそばでお世話してあげられる自信はないし……","ENG":"So I appreciate the offer, but... I don't think I'll be able to take care of you by your side like when I was a maid...","TWN":"很謝謝你的提議…但我沒把握可以像以前那樣常常陪在你身邊…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"…그래도 괜찮아?","JPN":"……それでも大丈夫？","ENG":"...Is that okay?","TWN":"…你沒關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그래도… 역시 내가 곁에 없으면 빈 자리가 클 것 같다고?","JPN":"でも……やっぱり私がそばにいないと寂しいって？","ENG":"You... think that you'll feel lonely if I'm not beside you?","TWN":"可是…我怕我不在你身邊，你會很空虛欸？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"크, 크흠!","JPN":"こ、こほん！","ENG":"K-kahem!","TWN":"咳，咳咳！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그럼… 줘, 계약서.","JPN":"じゃあ……出して、契約書。","ENG":"Then... give it here. That contract.","TWN":"那…好吧，契約書給我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"메이드 때처럼 봉사하는 건 힘들지도 모르겠지만, 네 전속 비서 정도는 되어 줄 테니까.","JPN":"メイドの時みたいに奉仕するのは難しいかもしれないけど、あんたの専属秘書ぐらいならしてあげる。","ENG":"It might be hard for me to serve you like I did when I was a maid, but I think I can manage to be your secretary at least.","TWN":"雖然無法像以前當女僕時那樣地服侍你，但至少可以成為你的專屬秘書。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};